{
  "name": "csv-cli",
  "version": "1.0.0",
  "private": true,
  "description": "Command-line tool for CSV parsing and statistics",
  "main": "dist/cli.js",
  "scripts": {
    "build": "tsc",
    "test": "node test.js"
  },
  "author": "",
  "license": "MIT"
}

declare const require: any;

export class CsvParser {
  private delimiter: string;

  constructor(options?: { delimiter?: string }) {
    this.delimiter = (options && options.delimiter) || ',';
  }

  parse(text: string): Record<string, string>[] {
    if (!text || !text.trim()) return [];
    const lines = text.replace(/\r\n/g, '\n').split('\n');
    const headerLine = lines[0];
    if (!headerLine) return [];
    const headers = this.splitRow(headerLine);
    const result: Record<string, string>[] = [];
    for (let i = 1; i < lines.length; i++) {
      const line = lines[i];
      if (!line.trim()) continue;
      const values = this.splitRow(line);
      const row: Record<string, string> = {};
      for (let j = 0; j < headers.length; j++) {
        row[headers[j]] = values[j] || '';
      }
      result.push(row);
    }
    return result;
  }

  stringify(rows: Record<string, string>[]): string {
    if (rows.length === 0) return "";
    const headers = Object.keys(rows[0]);
    const lines: string[] = [headers.map(h => this.quoteField(h)).join(this.delimiter)];
    for (const row of rows) {
      lines.push(headers.map(h => this.quoteField(String(row[h] ?? ""))).join(this.delimiter));
    }
    return lines.join('\n') + '\n';
  }

  private quoteField(field: string): string {
    if (field.indexOf(this.delimiter) >= 0 || field.indexOf('"') >= 0 || field.indexOf("\n") >= 0) {
      return '"' + field.replace(/"/g, '""') + '"';
    }
    return field;
  }

  private splitRow(line: string): string[] {
    const fields: string[] = [];
    let current = '';
    let inQuotes = false;
    let i = 0;
    while (i < line.length) {
      const ch = line[i];
      if (inQuotes) {
        if (ch === '"') {
          if (i + 1 < line.length && line[i + 1] === '"') {
            current += '"';
            i += 2;
          } else {
            inQuotes = false;
            i++;
          }
        } else {
          current += ch;
          i++;
        }
      } else {
        if (ch === '"') {
          inQuotes = true;
          i++;
        } else if (ch === this.delimiter) {
          fields.push(current);
          current = '';
          i++;
        } else {
          current += ch;
          i++;
        }
      }
    }
    fields.push(current);
    return fields;
  }
}

export class CsvFilter {
  private rows: Record<string, string>[];

  constructor(rows: Record<string, string>[]) {
    this.rows = rows;
  }

  where(predicate: (row: Record<string, string>) => boolean): Record<string, string>[] {
    return this.rows.filter(predicate);
  }

  select(columns: string[]): Record<string, string>[] {
    return this.rows.map(row => {
      const out: Record<string, string> = {};
      for (const col of columns) {
        out[col] = row[col] ?? '';
      }
      return out;
    });
  }

  sortBy(column: string): Record<string, string>[] {
    return [...this.rows].sort((a, b) => {
      const va = a[column] ?? '';
      const vb = b[column] ?? '';
      return va < vb ? -1 : va > vb ? 1 : 0;
    });
  }

  count(): number {
    return this.rows.length;
  }
}

declare const require: any;
declare const process: any;
const fs = require('node:fs');
const { CsvParser } = require('./csv');

function printHelp(): void {
  console.log('Usage:');
  console.log('  node dist/cli.js parse --input <file>');
  console.log('  node dist/cli.js stats --input <file>');
  console.log('  node dist/cli.js --help');
  console.log();
  console.log('Commands:');
  console.log('  parse   Parse CSV file and output JSON array');
  console.log('  stats   Show row count and column names');
  console.log('  --help  Show this help message');
}

function parseCommand(inputPath: string): void {
  const content = fs.readFileSync(inputPath, 'utf8');
  const parser = new CsvParser();
  const rows = parser.parse(content);
  const json = JSON.stringify(rows);
  process.stdout.write(json + '\n');
}

function statsCommand(inputPath: string): void {
  const content = fs.readFileSync(inputPath, 'utf8');
  const parser = new CsvParser();
  const rows = parser.parse(content);
  const columnNames = rows.length ? Object.keys(rows[0]) : [];
  console.log(`Rows: ${rows.length}`);
  console.log(`Columns: ${columnNames.join(', ')}`);
}

function main(): void {
  const args = process.argv.slice(2);
  if (args.length === 0) {
    printHelp();
    process.exit(1);
  }

  const helpIdx = args.indexOf('--help');
  if (helpIdx !== -1) {
    printHelp();
    process.exit(0);
  }

  const inputIdx = args.indexOf('--input');
  if (inputIdx === -1 || inputIdx === args.length - 1) {
    console.error('Error: --input <file> is required');
    process.exit(1);
  }

  const command = args[0];
  const inputPath = args[inputIdx + 1];

  if (command === 'parse') {
    parseCommand(inputPath);
  } else if (command === 'stats') {
    statsCommand(inputPath);
  } else {
    console.error(`Error: Unknown command '${command}'`);
    process.exit(1);
  }
}

main();
